import{_ as n}from"./plugin-vue_export-helper-DlAUqK2U.js";import{e as a,f as e,o as t}from"./app-_JojGnWZ.js";const o="/assets/2024-11-12-22-29-09-CLk5yn58.png",p={};function l(c,s){return t(),a("div",null,s[0]||(s[0]=[e('<h1 id="ue-热更" tabindex="-1"><a class="header-anchor" href="#ue-热更"><span>UE 热更</span></a></h1><h2 id="资源" tabindex="-1"><a class="header-anchor" href="#资源"><span>资源</span></a></h2><p>使用插件<a href="https://github.com/hxhb/HotPatcher" target="_blank" rel="noopener noreferrer">HotPatcher</a>，具体操作查看文档地址：<a href="https://imzlp.com/posts/17590/" target="_blank" rel="noopener noreferrer">https://imzlp.com/posts/17590/</a>。</p><p>遇到一个问题：Io Store不能被打开:</p><figure><img src="'+o+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>所以在<code>Project Settings -&gt; Packaging -&gt; Use Io Stroe</code> 要取消，导出的pkg包就可以更新成功。</p><p>至于为什么没被打开，是因为<code>CookPatchAssets</code>打开时，Io Store是不被可用的。</p><h3 id="蓝图热更实操-windows-dev-测试包" tabindex="-1"><a class="header-anchor" href="#蓝图热更实操-windows-dev-测试包"><span>蓝图热更实操（Windows Dev 测试包）</span></a></h3><p>目标：改一两个蓝图后不重新完整打包，把改动做成补丁 pak 塞进已有测试包里验证。下面记录 UE5.4 上一套跑通的流程。</p><h4 id="原理" tabindex="-1"><a class="header-anchor" href="#原理"><span>原理</span></a></h4><ul><li>测试包内容是<strong>纯 <code>.pak</code></strong>（没开 IoStore、没有 <code>.ucas/.utoc</code>、未签名未加密）。UE 启动时把 <code>Content\\Paks\\</code> 下所有 <code>.pak</code> 按优先级挂载，<strong>文件名带 <code>_P</code> 后缀的补丁包优先级最高</strong>，覆盖基础包里同路径的资产。</li><li>所以资产热更<strong>不用写任何 C++</strong>：把 <code>*_P.pak</code> 拷进 <code>Content\\Paks\\</code>，游戏启动自动加载并覆盖。</li><li>cook 产物只取决于<strong>平台（Windows）+ 引擎版本</strong>，<strong>与 build 配置（Development / Shipping / DebugGame）无关</strong>。用 Development 基础包挂 Development 编辑器 cook 出的补丁包，完全兼容。</li></ul><h4 id="一次性接入" tabindex="-1"><a class="header-anchor" href="#一次性接入"><span>一次性接入</span></a></h4><p>前置：</p><ul><li><code>.uproject</code> 里启用 HotPatcher 插件。</li><li>命令行 cook 用的编辑器可执行文件，必须和你编译过 HotPatcher 插件的那套配置一致。比如插件只在 DebugGame editor 下编过，就得用 <code>UnrealEditor-Win64-DebugGame-Cmd.exe</code>；编了 Development editor 才能用默认的 <code>UnrealEditor-Cmd.exe</code>。用没编过插件的配置去 cook，会在启动时因插件加载失败。</li></ul><p>打基础包（<code>RunUAT BuildCookRun</code>，<code>-clientconfig=Development</code>，<code>-build -cook -stage -pak -archive</code>）时有两个坑要提前避开：</p><ul><li><strong>别加 <code>-nocompileeditor</code></strong>：cook 步骤会启动对应配置的编辑器跑 cook commandlet。如果只编了 DebugGame 编辑器，又不让 UAT 顺带编 Development 编辑器 + 插件，cook 启动时就会因插件加载失败。</li><li>带上 <code>-AdditionalCookerOptions=-noxgeshadercompile</code>：强制<strong>本地</strong>编译 shader，避开分布式 shader 编译器死锁（见下文坑 5）。</li></ul><p>产物里两样东西：启动器 <code>MyGame.exe</code>，内容目录 <code>Content\\Paks\\</code>（几十 GB 的 pakchunk*.pak）。</p><p>基准清单（base manifest）用 <code>-run=HotRelease</code> 生成，产物是一份含全工程所有资产 MD5 的大 JSON（几十 MB）。它只给<strong>全量 diff 补丁</strong>用；<strong>日常单蓝图迭代不需要它</strong>（见下节快速路径），此处仅为完整性保留。</p><h4 id="日常-快速单资产补丁-推荐" tabindex="-1"><a class="header-anchor" href="#日常-快速单资产补丁-推荐"><span>日常：快速单资产补丁（推荐）</span></a></h4><p>全量 diff 路径太慢会卡死，日常一律走这条。涉及三个文件：</p><table><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><code>GeneratePatchFast.bat</code></td><td>运行脚本（<code>-run=HotPatcher</code> + <code>-AddAssetsByFile</code> + <code>-noxgeshadercompile</code>）</td></tr><tr><td><code>PatchConfig_Fast.json</code></td><td>精简配置：<code>bByBaseVersion:false</code>，<code>assetIncludeFilters:[]</code>，不做全量扫描/diff</td></tr><tr><td><code>addassets_patch.txt</code></td><td>要打补丁的资产清单，一行一个<strong>长包名</strong></td></tr></tbody></table><p>步骤：</p><ol><li><strong>改蓝图，在编辑器里存盘（Ctrl+S / Save All）。</strong> 补丁工具从<strong>磁盘上的 <code>.uasset</code></strong> 读数据，不读编辑器内存——不存盘 = 改动不进包。</li><li><strong>编辑 <code>addassets_patch.txt</code></strong>，填资产长包名（<code>/Game/...</code>，<strong>不带 <code>.uasset</code> 后缀</strong>，一行一个）。例如：<div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">/Game/Characters/Hero/Weapon/Unarmed/GameplayAbilities/AttackLight/BP_TestSpawn</span>
<span class="line">/Game/Characters/Hero/Weapon/Unarmed/GameplayAbilities/AttackLight/GA_Unarmed_AttackLight</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>长包名 = 磁盘路径里 <code>.../Content/</code> 之后的部分，前面换成 <code>/Game</code>，去掉 <code>.uasset</code>。<br> 例：<code>&lt;Project&gt;\\Content\\Characters\\Hero\\...\\BP_TestSpawn.uasset</code> → <code>/Game/Characters/Hero/...\\BP_TestSpawn</code></p></blockquote></li><li><strong>运行 <code>GeneratePatchFast.bat</code></strong>。只 cook + pak 清单里的资产，正常几秒出包（实测 &lt;1 秒完成 diff+cook+pak）。</li><li><strong>产物</strong>：<code>Saved\\HotPatcher\\Patch\\Patch_001\\Windows\\Patch_001_Windows_001_P.pak</code></li><li><strong>把这个 <code>_P.pak</code> 拷进测试包的</strong> <code>Content\\Paks\\</code>。</li><li><strong>运行 <code>MyGame.exe</code></strong> 验证改动是否生效。</li></ol><p>判断成功：</p><ul><li><strong>别看 bat 的 exit code</strong>（它可能报 <code>FAILED exit code 1</code> 但其实成功了，见坑 6）。</li><li>以下两条同时满足即成功：日志里有 <code>Export Patch Misstion is Successed, return 0!</code>；<code>Saved\\HotPatcher\\Patch\\Patch_001\\Windows\\</code> 下生成了 <code>*_P.pak</code>。</li><li>想确认 pak 里到底打了哪些文件，看同目录的 <code>*_P_PakCommands.txt</code>（列出每个进包的 <code>.uasset/.uexp</code>）。</li></ul><h4 id="全量-diff-补丁-备用-不推荐日常" tabindex="-1"><a class="header-anchor" href="#全量-diff-补丁-备用-不推荐日常"><span>全量 diff 补丁（备用，不推荐日常）</span></a></h4><p><code>GeneratePatch.bat</code> + 全量配置会扫全 <code>/Game</code>（十几万资产）逐个算 MD5，跟基准清单 diff，自动找出所有改动并按 chunk 分别出包。适用于一次改了很多资产、懒得手写清单、要按 chunk 分包的场景。代价是在本机磁盘上极慢——实测<strong>卡死 2 小时零进展</strong>（见坑 1），除非确有需要否则别用。</p><h4 id="踩过的坑" tabindex="-1"><a class="header-anchor" href="#踩过的坑"><span>踩过的坑</span></a></h4><p><strong>坑 1：全量 diff 卡死（最坑）。</strong> 全量配置每次都扫十几万资产逐个读盘算 MD5，只为找出改的那几个。在本机磁盘 I/O 下挂了 2 小时零进展（日志停在 <code>FAssetDependenciteParser Asset Num</code>，内存从 16.5GB 塌到 1.8GB、CPU 只剩个位数）。日常改几个蓝图一律用快速路径。</p><p><strong>坑 2：commandlet 名字是 <code>HotPatcher</code> 不是 <code>HotPatch</code>。</strong> 补丁 commandlet 类是 <code>UHotPatcherCommandlet</code>，命令行要写 <code>-run=HotPatcher</code>。写成 <code>-run=HotPatch</code> 会报 <code>HotPatchCommandlet looked like a commandlet, but we could not find the class.</code> 并空跑退出。（生成基准清单的是另一个：<code>-run=HotRelease</code> → <code>UHotReleaseCommandlet</code>。）</p><p><strong>坑 3：改完必须存盘。</strong> 补丁工具读磁盘上的 <code>.uasset</code>，不是编辑器内存里的未保存状态。改完不 Ctrl+S，补丁包里就是旧内容。</p><p><strong>坑 4：cook 用的编辑器配置必须和编过插件的一致。</strong> 插件只在 DebugGame editor 下编过，命令行就必须用 <code>UnrealEditor-Win64-DebugGame-Cmd.exe</code>；用没编过插件的配置会因插件加载失败。</p><p><strong>坑 5：分布式 shader 编译死锁。</strong> 打基础包 cook 时，分布式 shader 编译器可能在最后几十个材质上死锁（任务派给远程 agent 后不返回，<code>IsCachedCookedPlatformDataLoaded</code> 永远 false，编辑器冻住）。所有涉及 cook 的命令都加 <code>-noxgeshadercompile</code>（或 <code>-AdditionalCookerOptions=-noxgeshadercompile</code>），强制本地编译。</p><p><strong>坑 6：bat 报 <code>FAILED exit code 1</code> 是假警报。</strong> 补丁进程退出码可能是 1，但 HotPatcher 自己 <code>Misstion is Successed, return 0</code>、pak 也正常生成。exit 1 来自引擎退出时统计到 1 个 error，实为 <code>HttpListener unable to bind to 127.0.0.1:3000</code>（开着的编辑器占用了 3000 端口）或 <code>libcurl error 35 (SSL connect error)</code>（telemetry 上报被网络拦截），两者都跟 pak 无关。判定成功以「日志有 Successed + pak 文件存在」为准。</p><p><strong>坑 7：热更不需要 C++。</strong> 基础包是纯 pak（无 IoStore、未签名未加密），<code>_P.pak</code> 丢进 <code>Content\\Paks\\</code> 就自动高优先级挂载覆盖，无需改 GameInstance/挂载逻辑。</p><p><strong>坑 8：C++ / <code>.cpp</code> 改动无法用 pak 热更。</strong> 补丁只能覆盖<strong>资产</strong>（<code>.uasset</code>）。C++ 代码改动（<code>.cpp/.h</code>）不在 pak 覆盖范围，必须重新编译 + 重打包。</p><p><strong>坑 9（仅命令行/脚本编辑时）：<code>.bat</code> 需 CRLF + 纯 ASCII。</strong> 在 Git-Bash/MSYS 里生成或编辑这些 bat 时，行尾必须是 CRLF（否则 cmd 会把参数当成独立命令乱跑），内容保持纯 ASCII（别混中文/BOM/<code>chcp</code>/<code>^</code> 续行）。通过 Bash 调 <code>cmd.exe /c</code> 或 <code>taskkill</code> 时，前面加 <code>MSYS_NO_PATHCONV=1</code>，否则 <code>/c</code>、<code>/F</code> 等 flag 会被 MSYS 当路径转换掉。直接双击运行 bat 的用户无需关心此条。</p><h4 id="脚本与配置" tabindex="-1"><a class="header-anchor" href="#脚本与配置"><span>脚本与配置</span></a></h4><p>下面几个脚本/配置都放在工程的 <code>HotPatcherConfig\\</code> 下。路径里 <code>&lt;Engine&gt;</code> 是引擎根目录、<code>&lt;Project&gt;</code> 是工程根目录，<code>MyGame</code> 是工程名，按自己项目替换。</p><p>日常改一两个蓝图只会用到前三个：<code>GeneratePatchFast.bat</code>、<code>PatchConfig_Fast.json</code>、<code>addassets_patch.txt</code>。</p><p><code>addassets_patch.txt</code>——要打补丁的资产长包名，一行一个，不带 <code>.uasset</code>：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">/Game/Characters/Hero/Weapon/Unarmed/GameplayAbilities/AttackLight/BP_TestSpawn</span>
<span class="line">/Game/Characters/Hero/Weapon/Unarmed/GameplayAbilities/AttackLight/GA_Unarmed_AttackLight</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>PatchConfig_Fast.json</code>——快速补丁配置，<code>bByBaseVersion:false</code> + 空 <code>assetIncludeFilters</code>，不做全量扫描/diff：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;versionId&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Patch_001&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bByBaseVersion&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bEnableExternFilesDiff&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;bEnableChunk&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bCreateDefaultChunk&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;bCookPatchAssets&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bStorageNewRelease&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bStorageDeletedAssetsToNewReleaseJson&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;pakTargetPlatforms&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token string">&quot;Windows&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;bCustomPakNameRegular&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;pakNameRegular&quot;</span><span class="token operator">:</span> <span class="token string">&quot;{VERSION}_{CHUNKNAME}_{PLATFORM}_001_P&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bCustomPakPathRegular&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;pakPathRegular&quot;</span><span class="token operator">:</span> <span class="token string">&quot;{CHUNKNAME}/{PLATFORM}&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;savePath&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;&lt;Project&gt;/Saved/HotPatcher/Patch&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;assetScanConfig&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token property">&quot;bPackageTracker&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;bAnalysisFilterDependencies&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;bIncludeHasRefAssetsOnly&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;bForceSkipContent&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;chunkInfos&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>GeneratePatchFast.bat</code>——只 cook + pak 清单里的资产，几秒出包。注意用的 Cmd 要和编译过 HotPatcher 插件的配置一致（这里是 DebugGame）：</p><div class="language-bat line-numbers-mode" data-highlighter="prismjs" data-ext="bat"><pre><code><span class="line">@echo off</span>
<span class="line">setlocal</span>
<span class="line"></span>
<span class="line">REM HotPatcher - 快速单资产补丁（不做全 /Game diff）</span>
<span class="line">REM 只打 addassets_patch.txt 里列的资产（-AddAssetsByFile），</span>
<span class="line">REM Fast 配置里 bByBaseVersion=false 所以不跑 base diff。</span>
<span class="line">REM 改完资产要先在编辑器 Ctrl+S 存盘。</span>
<span class="line">REM -noxgeshadercompile: 强制本地编译 shader，避开分布式编译死锁。</span>
<span class="line">REM 用 DebugGame-Cmd 以匹配唯一编译过的 HotPatcher 配置。</span>
<span class="line"></span>
<span class="line">set &quot;ENGINE_CMD=&lt;Engine&gt;\\Engine\\Binaries\\Win64\\UnrealEditor-Win64-DebugGame-Cmd.exe&quot;</span>
<span class="line">set &quot;PROJECT=&lt;Project&gt;\\MyGame.uproject&quot;</span>
<span class="line">set &quot;CONFIG=&lt;Project&gt;\\HotPatcherConfig\\PatchConfig_Fast.json&quot;</span>
<span class="line">set &quot;ADDASSETS=&lt;Project&gt;\\HotPatcherConfig\\addassets_patch.txt&quot;</span>
<span class="line"></span>
<span class="line">if not exist &quot;%ENGINE_CMD%&quot; ( echo [ERROR] Cmd not found: %ENGINE_CMD% &amp; exit /b 1 )</span>
<span class="line">if not exist &quot;%PROJECT%&quot;    ( echo [ERROR] uproject not found: %PROJECT% &amp; exit /b 1 )</span>
<span class="line">if not exist &quot;%CONFIG%&quot;     ( echo [ERROR] config not found: %CONFIG% &amp; exit /b 1 )</span>
<span class="line">if not exist &quot;%ADDASSETS%&quot;  ( echo [ERROR] addassets not found: %ADDASSETS% &amp; exit /b 1 )</span>
<span class="line"></span>
<span class="line">&quot;%ENGINE_CMD%&quot; &quot;%PROJECT%&quot; -run=HotPatcher -config=&quot;%CONFIG%&quot; -AddAssetsByFile=&quot;%ADDASSETS%&quot; -noxgeshadercompile -unattended -stdout -UTF8Output -NoLogTimes</span>
<span class="line"></span>
<span class="line">set &quot;EXITCODE=%ERRORLEVEL%&quot;</span>
<span class="line">if &quot;%EXITCODE%&quot;==&quot;0&quot; (</span>
<span class="line">    echo DONE. 产物: %Project%\\Saved\\HotPatcher\\Patch\\ 下的 *_001_P.pak</span>
<span class="line">) else (</span>
<span class="line">    echo exit code %EXITCODE% —— 别只看这个，以「日志有 Successed + pak 存在」为准</span>
<span class="line">)</span>
<span class="line">endlocal</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>PackageWindowsDev.bat</code>——打 Development Win64 基础包（<code>build+cook+stage+pak+archive</code> 一把梭）。别加 <code>-nocompileeditor</code>：</p><div class="language-bat line-numbers-mode" data-highlighter="prismjs" data-ext="bat"><pre><code><span class="line">@echo off</span>
<span class="line">setlocal</span>
<span class="line"></span>
<span class="line">REM 打 Development Win64 基础包，作为 HotPatcher 测试底包。</span>
<span class="line">REM cook 产物只取决于 平台+引擎版本，与 build 配置无关，</span>
<span class="line">REM 所以这个 Development 底包能挂后面生成的 _P 补丁包。</span>
<span class="line">REM 别加 -nocompileeditor：cook 会启动 Development 编辑器跑 cook</span>
<span class="line">REM commandlet，本工程只编了 DebugGame 编辑器，不让 UAT 顺带编</span>
<span class="line">REM Development 编辑器 + 插件的话，cook 启动即失败。</span>
<span class="line"></span>
<span class="line">set &quot;UAT=&lt;Engine&gt;\\Engine\\Build\\BatchFiles\\RunUAT.bat&quot;</span>
<span class="line">set &quot;PROJECT=&lt;Project&gt;\\MyGame.uproject&quot;</span>
<span class="line">set &quot;ARCHIVE=&lt;Project&gt;\\LocalBuilds&quot;</span>
<span class="line"></span>
<span class="line">if not exist &quot;%UAT%&quot; ( echo [ERROR] RunUAT.bat not found: %UAT% &amp; exit /b 1 )</span>
<span class="line"></span>
<span class="line">REM -AdditionalCookerOptions=-noxgeshadercompile: 强制本地编译 shader。</span>
<span class="line">REM 分布式 shader 编译器曾在最后几十个材质上死锁（任务派给远程 agent</span>
<span class="line">REM 不返回），本地编译避开它。没加 -clean，已 cook 的包会复用。</span>
<span class="line">call &quot;%UAT%&quot; BuildCookRun -project=&quot;%PROJECT%&quot; -noP4 -platform=Win64 -clientconfig=Development -build -cook -stage -pak -archive -archivedirectory=&quot;%ARCHIVE%&quot; -utf8output -unattended -AdditionalCookerOptions=-noxgeshadercompile</span>
<span class="line"></span>
<span class="line">set &quot;EXITCODE=%ERRORLEVEL%&quot;</span>
<span class="line">if &quot;%EXITCODE%&quot;==&quot;0&quot; (</span>
<span class="line">    echo DONE. 产物在 %ARCHIVE%\\Windows\\，含 MyGame\\Content\\Paks\\*.pak，MyGame.exe 可启动</span>
<span class="line">) else (</span>
<span class="line">    echo FAILED exit code %EXITCODE%，往上翻 Error/Exception</span>
<span class="line">)</span>
<span class="line">endlocal</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>GenerateBaseRelease.bat</code>——生成基准清单（全量 diff 补丁才需要，日常用不到）：</p><div class="language-bat line-numbers-mode" data-highlighter="prismjs" data-ext="bat"><pre><code><span class="line">@echo off</span>
<span class="line">setlocal</span>
<span class="line"></span>
<span class="line">REM HotPatcher - 生成基准 Release 清单（Base_001）。</span>
<span class="line">REM 命令行跑 HotRelease commandlet，等价于 Release 页点 Export Release。</span>
<span class="line">REM 产物: Saved\\HotPatcher\\ 下含全工程资产 hash 的清单。</span>
<span class="line">REM 同样必须用编译过插件的那套 Cmd（这里 DebugGame）。</span>
<span class="line"></span>
<span class="line">set &quot;ENGINE_CMD=&lt;Engine&gt;\\Engine\\Binaries\\Win64\\UnrealEditor-Win64-DebugGame-Cmd.exe&quot;</span>
<span class="line">set &quot;PROJECT=&lt;Project&gt;\\MyGame.uproject&quot;</span>
<span class="line">set &quot;CONFIG=&lt;Project&gt;\\HotPatcherConfig\\Base_001_Release.json&quot;</span>
<span class="line"></span>
<span class="line">if not exist &quot;%ENGINE_CMD%&quot; ( echo [ERROR] Cmd not found: %ENGINE_CMD% &amp; exit /b 1 )</span>
<span class="line">if not exist &quot;%PROJECT%&quot;    ( echo [ERROR] uproject not found: %PROJECT% &amp; exit /b 1 )</span>
<span class="line">if not exist &quot;%CONFIG%&quot;     ( echo [ERROR] config not found: %CONFIG% &amp; exit /b 1 )</span>
<span class="line"></span>
<span class="line">&quot;%ENGINE_CMD%&quot; &quot;%PROJECT%&quot; -run=HotRelease -config=&quot;%CONFIG%&quot; -unattended -stdout -UTF8Output -NoLogTimes</span>
<span class="line"></span>
<span class="line">set &quot;EXITCODE=%ERRORLEVEL%&quot;</span>
<span class="line">if &quot;%EXITCODE%&quot;==&quot;0&quot; ( echo DONE. 清单在 %Project%\\Saved\\HotPatcher\\ ) else ( echo FAILED exit code %EXITCODE% )</span>
<span class="line">endlocal</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>GeneratePatch.bat</code> + <code>PatchConfig.json</code>——全量 diff 补丁（备用，慢，易卡）。脚本结构同上，把 <code>-config</code> 换成全量配置、去掉 <code>-AddAssetsByFile</code>：</p><div class="language-bat line-numbers-mode" data-highlighter="prismjs" data-ext="bat"><pre><code><span class="line">&quot;%ENGINE_CMD%&quot; &quot;%PROJECT%&quot; -run=HotPatcher -config=&quot;&lt;Project&gt;\\HotPatcherConfig\\PatchConfig.json&quot; -unattended -stdout -UTF8Output -NoLogTimes</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>全量配置 <code>PatchConfig.json</code> 的关键点：<code>bByBaseVersion:true</code> 指向基准清单，开 chunk，扫全 <code>/Game</code> 逐个算 MD5 做 diff，再按 chunk 分包。示意（chunk 路径按自己工程目录结构填）：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;versionId&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Patch_001&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bByBaseVersion&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;baseVersion&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;filePath&quot;</span><span class="token operator">:</span> <span class="token string">&quot;&lt;Project&gt;/Saved/HotPatcher/Base_001/Base_001_Release.json&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bEnableExternFilesDiff&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;bEnableChunk&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bCreateDefaultChunk&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bCookPatchAssets&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bStorageNewRelease&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;pakTargetPlatforms&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token string">&quot;Windows&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bCustomPakNameRegular&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;pakNameRegular&quot;</span><span class="token operator">:</span> <span class="token string">&quot;{VERSION}_{CHUNKNAME}_{PLATFORM}_001_P&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;bCustomPakPathRegular&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;pakPathRegular&quot;</span><span class="token operator">:</span> <span class="token string">&quot;{CHUNKNAME}/{PLATFORM}&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;savePath&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;&lt;Project&gt;/Saved/HotPatcher/Patch&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;assetScanConfig&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token property">&quot;bPackageTracker&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;bForceSkipContent&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">            <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/__ExternalActors__&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/__ExternalObjects__&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_DO_NOT_SHIP&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/Developers&quot;</span> <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">]</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">    <span class="token property">&quot;chunkInfos&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token punctuation">{</span> <span class="token property">&quot;chunkName&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Gameplay&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_BP&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_AbilitySystem&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_GameFramework&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_Characters&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">{</span> <span class="token property">&quot;chunkName&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Data&quot;</span><span class="token punctuation">,</span>     <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_Data&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_StringTable&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">{</span> <span class="token property">&quot;chunkName&quot;</span><span class="token operator">:</span> <span class="token string">&quot;UI&quot;</span><span class="token punctuation">,</span>       <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_UI&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">{</span> <span class="token property">&quot;chunkName&quot;</span><span class="token operator">:</span> <span class="token string">&quot;FX_Audio&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_VFX&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_SFX&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_Sound&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">{</span> <span class="token property">&quot;chunkName&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Scene&quot;</span><span class="token punctuation">,</span>    <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/_Scene&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/Levels&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game/Map&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">{</span> <span class="token property">&quot;chunkName&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Art_Base&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;bAnalysisFilterDependencies&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token property">&quot;assetRegistryDependencyTypes&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token string">&quot;Packages&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIncludeFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token punctuation">{</span> <span class="token property">&quot;path&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Game&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token property">&quot;assetIgnoreFilters&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span> <span class="token string">&quot;把上面各 chunk 的 include 路径全列进来，避免重复进包&quot;</span> <span class="token punctuation">]</span> <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">]</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><code>Art_Base</code> 用「include 全 <code>/Game</code> + ignore 掉其它所有 chunk 的路径」兜底剩余美术资产，并靠 <code>bAnalysisFilterDependencies</code> 把依赖也带上。</p></blockquote><h2 id="代码" tabindex="-1"><a class="header-anchor" href="#代码"><span>代码</span></a></h2><p>比较成熟的解决方案：</p><ul><li><a href="https://github.com/Tencent/puerts" target="_blank" rel="noopener noreferrer">puerts</a><ul><li><a href="https://www.bilibili.com/video/BV1vW4y117Kh" target="_blank" rel="noopener noreferrer">鸣潮一些实践建议</a></li><li><a href="https://www.bilibili.com/video/BV1ms4y1T7Q" target="_blank" rel="noopener noreferrer">https://www.bilibili.com/video/BV1ms4y1T7Q</a></li></ul></li><li><a href="https://github.com/Tencent/UnLua" target="_blank" rel="noopener noreferrer">UnLua</a></li></ul><h3 id="puerts" tabindex="-1"><a class="header-anchor" href="#puerts"><span>puerts</span></a></h3><ul><li>安装TS：<code>npm install -g typescript</code></li><li>放到插件目录后查看<code>YouProject/Plugins/Puerts/Source/JsEnv/JsEnv.Build.cs</code>设置的V8版本，再对应去<a href="https://github.com/puerts/backend-v8/releases/" target="_blank" rel="noopener noreferrer">下载</a></li><li>解压到<code>YouProject/Plugins/Puerts/ThirdPart</code>，并在JsEnv.build.cs中修改UseV8Version设置为你所下载的版本。</li><li>在<code>YouProject/Plugins/Puerts</code>目录下运行<code>node ./enable_puerts_module.js</code></li><li>在<code>YouProject</code>目录下运行<code>npm init -y</code></li><li>在<code>YouProject/package.json</code>中添加</li></ul><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line">  <span class="token property">&quot;scripts&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;build&quot;</span><span class="token operator">:</span> <span class="token string">&quot;tsc -p tsconfig.json&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;watch&quot;</span><span class="token operator">:</span> <span class="token string">&quot;tsc -p tsconfig.json --watch&quot;</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>生成工程，启动引擎，点击运行游戏按钮旁边蓝色按键生成中间类。或者在引擎中运行<code>Puerts.Gen</code>命令</li><li>在<code>YouProject</code>目录下运行<code>npm run build</code></li></ul><h4 id="ue-load报错" tabindex="-1"><a class="header-anchor" href="#ue-load报错"><span>UE.Load报错</span></a></h4><p>报错：</p><div class="language-log line-numbers-mode" data-highlighter="prismjs" data-ext="log"><pre><code><span class="line"><span class="token property">Puerts:</span> <span class="token property">Error:</span> <span class="token operator">(</span><span class="token number">0x0000024DFC84E050</span><span class="token operator">)</span> TypeError<span class="token operator">:</span> Cannot read</span>
<span class="line">  properties of undefined <span class="token operator">(</span>reading <span class="token string">&#39;Load&#39;</span><span class="token operator">)</span></span>
<span class="line">      at <span class="token file-path string">F:\\Learn\\PuertsLearn\\PuerTSDemo\\Content\\JavaScript\\Blueprints\\BP_Te</span></span>
<span class="line">  stActor<span class="token punctuation">.</span>js<span class="token operator">:</span><span class="token number">38</span><span class="token operator">:</span><span class="token number">19</span></span>
<span class="line">      at executeModule <span class="token operator">(</span><span class="token file-path string">F:\\Learn\\PuertsLearn\\PuerTSDemo\\Content\\JavaScript\\p</span></span>
<span class="line">  uerts\\modular<span class="token punctuation">.</span>js<span class="token operator">:</span><span class="token number">70</span><span class="token operator">:</span><span class="token number">9</span><span class="token operator">)</span></span>
<span class="line">      at require <span class="token operator">(</span><span class="token file-path string">F:\\Learn\\PuertsLearn\\PuerTSDemo\\Content\\JavaScript\\puerts\\</span></span>
<span class="line">  modular<span class="token punctuation">.</span>js<span class="token operator">:</span><span class="token number">183</span><span class="token operator">:</span><span class="token number">29</span><span class="token operator">)</span></span>
<span class="line">      at <span class="token file-path string">F:\\Learn\\PuertsLearn\\PuerTSDemo\\Content\\JavaScript\\Main.js</span><span class="token operator">:</span><span class="token number">3</span><span class="token operator">:</span><span class="token number">1</span></span>
<span class="line">      at executeModule <span class="token operator">(</span><span class="token file-path string">F:\\Learn\\PuertsLearn\\PuerTSDemo\\Content\\JavaScript\\p</span></span>
<span class="line">  uerts\\modular<span class="token punctuation">.</span>js<span class="token operator">:</span><span class="token number">70</span><span class="token operator">:</span><span class="token number">9</span><span class="token operator">)</span></span>
<span class="line">      at require <span class="token operator">(</span><span class="token file-path string">F:\\Learn\\PuertsLearn\\PuerTSDemo\\Content\\JavaScript\\puerts\\</span></span>
<span class="line">  modular<span class="token punctuation">.</span>js<span class="token operator">:</span><span class="token number">183</span><span class="token operator">:</span><span class="token number">29</span><span class="token operator">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>根本原因：你使用的 TypeScript 6.0.2 默认强制启用 <code>esModuleInterop</code>，导致 <code>import * as UE from &#39;ue&#39;</code> 被编译为 <code>__importStar(require(&quot;ue&quot;))</code><br> 而不是直接 <code>require(&quot;ue&quot;)</code>。</p><p><code> __importStar</code> 会把 PuerTS 的 UE 模块（一个依赖 Proxy 实现懒加载的对象）拷贝成一个普通对象，Proxy 的 get trap 不再生效。UE.Class<br> 没有被预先注册（它需要在访问时通过 Proxy 触发 <code>loadUEType(&quot;Class&quot;)</code> 才能加载），所以返回 undefined。</p><p>修复：在<code> tsconfig.json</code> 中添加了两个选项：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line">  <span class="token property">&quot;esModuleInterop&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;ignoreDeprecations&quot;</span><span class="token operator">:</span> <span class="token string">&quot;6.0&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>这样 <code>import * as UE</code> 会直接编译为 <code>const UE = require(&quot;ue&quot;)</code>，保留 Proxy 懒加载机制。</p><p>注意 esModuleInterop: false 在 TS 7.0 将被移除，届时可能需要 PuerTS 官方适配（比如将 UE 模块的 __esModule 设为<br> true，或者换用其他模块加载方式）。</p><p>另一种方案是锁定TS的版本，在<code>package.json</code>中添加</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"> <span class="token property">&quot;devDependencies&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;typescript&quot;</span><span class="token operator">:</span> <span class="token string">&quot;5.8&quot;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后 输入<code>npm install</code> 即可。</p><h4 id="关于gc的问题" tabindex="-1"><a class="header-anchor" href="#关于gc的问题"><span>关于GC的问题</span></a></h4><p>暂时不解决把</p><ul><li><a href="https://github.com/Devil-Beichen/Puerts_Gas_Game_01/tree/master" target="_blank" rel="noopener noreferrer">https://github.com/Devil-Beichen/Puerts_Gas_Game_01/tree/master</a></li><li><a href="https://github.com/KodakkuDeng/AI_UE5" target="_blank" rel="noopener noreferrer">https://github.com/KodakkuDeng/AI_UE5</a></li><li><a href="https://github.com/chexiongsheng/BlockBreakerStarter/tree/master" target="_blank" rel="noopener noreferrer">https://github.com/chexiongsheng/BlockBreakerStarter/tree/master</a></li></ul>`,77)]))}const u=n(p,[["render",l],["__file","HotFix.html.vue"]]),d=JSON.parse('{"path":"/GameEngine/Unreal/manual/HotFix.html","title":"UE 热更","lang":"en-US","frontmatter":{"date":"2024-07-12T18:03:06.000Z","tag":["Unreal Engine"]},"git":{"createdTime":1731424694000,"updatedTime":1782898965000,"contributors":[{"name":"BanMing","username":"BanMing","email":"ban-ming@foxmail.com","commits":7,"url":"https://github.com/BanMing"},{"name":"Claude Opus 4.7","username":"Claude Opus 4.7","email":"noreply@anthropic.com","commits":1,"url":"https://github.com/Claude Opus 4.7"}]},"readingTime":{"minutes":10.9,"words":3269},"filePathRelative":"GameEngine/Unreal/manual/HotFix.md","localizedDate":"July 12, 2024","excerpt":"\\n<h2>资源</h2>\\n<p>使用插件<a href=\\"https://github.com/hxhb/HotPatcher\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">HotPatcher</a>，具体操作查看文档地址：<a href=\\"https://imzlp.com/posts/17590/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">https://imzlp.com/posts/17590/</a>。</p>\\n<p>遇到一个问题：Io Store不能被打开:</p>\\n<figure><figcaption></figcaption></figure>"}');export{u as comp,d as data};
